    82→/**
    83→ * Notes Store State
    84→ */
    85→interface NotesStore {
    86→  // State
    87→  notes: Record<string, Note>; // Map of note ID -> Note
    88→  activeNoteId: string | null; // Currently open note
    89→  sortConfig: NoteSortConfig;
    90→  filter: NoteFilter;
    91→  customNoteTemplates: NoteTemplate[]; // User-created templates
    92→
    93→  // Actions - CRUD
    94→  createNote: (params?: Partial<Note>) => Note;
    95→  getNote: (id: string) => Note | undefined;
    96→  updateNote: (id: string, updates: NoteUpdate) => void;
    97→  deleteNote: (id: string) => void;
    98→  duplicateNote: (id: string) => Note | null;
    99→
   100→  // Actions - Bulk operations
   101→  deleteNotes: (ids: string[]) => void;
   102→  moveNotesToFolder: (noteIds: string[], folderId: string | null) => void;
   103→  archiveNotes: (noteIds: string[]) => void;
   104→  unarchiveNotes: (noteIds: string[]) => void;
   105→
   106→  // Actions - Queries
   107→  getAllNotes: () => Note[];
   108→  getFilteredNotes: () => Note[];
   109→  getNotesByFolder: (folderId: string | null) => Note[];
   110→  getNotesBy: (predicate: (note: Note) => boolean) => Note[];
   111→  searchNotes: (query: string) => Note[];
   112→
   113→  // Actions - Pin/Archive/Favorite
   114→  togglePin: (id: string) => void;
   115→  toggleArchive: (id: string) => void;
   116→  toggleFavorite: (id: string) => void;
   117→
   118→  // Actions - Tags
   119→  addTag: (id: string, tag: string) => void;
   120→  removeTag: (id: string, tag: string) => void;
   121→  getAllTags: () => string[];
   122→  getTagUsageCounts: () => Map<string, number>;
   123→  renameTag: (oldTag: string, newTag: string) => void;
   124→  mergeTags: (sourceTags: string[], targetTag: string) => void;
   125→  deleteTag: (tag: string) => void;
   126→  renameTagGlobally: (oldTag: string, newTag: string) => void;
   127→  deleteTagGlobally: (tag: string) => void;
   128→
   129→  // P2: Bulk tag operations
   130→  bulkAddTag: (noteIds: string[], tag: string) => void;
   131→  bulkRemoveTag: (noteIds: string[], tag: string) => void;
   132→  replaceTag: (oldTag: string, newTag: string) => void;
   133→
   134→  // Actions - UI state
   135→  setActiveNote: (id: string | null) => void;
   136→  setSortConfig: (config: NoteSortConfig) => void;
   137→  setFilter: (filter: NoteFilter) => void;
   138→
   139→  // Actions - Utility
   140→  getNoteCount: () => number;
   141→  getNotesInFolder: (folderId: string | null) => Note[];
   142→  exportNotes: () => Note[];
   143→  importNotes: (notes: Note[], merge: boolean) => void;
   144→  clearAllNotes: () => void;
   145→
   146→  // Actions - Backlinks (Phase 4)
   147→  getBacklinks: (noteId: string) => Note[];
   148→  updateLinkedNotes: (noteId: string, content: string) => void;
   149→
   150→  // P1: Unlinked mentions - Convert text to wiki link
   151→  convertToWikiLink: (noteId: string, position: number, targetTitle: string) => void;
   152→
   153→  // Actions - Templates (Phase 4)
   154→  getNoteTemplates: () => NoteTemplate[];
   155→  createNoteFromTemplate: (templateId: string) => Note | null;
   156→  createNoteTemplate: (params: Partial<NoteTemplate>) => NoteTemplate;
   157→  updateNoteTemplate: (id: string, updates: Partial<NoteTemplate>) => void;
   158→  deleteNoteTemplate: (id: string) => void;
   159→  getNoteTemplate: (id: string) => NoteTemplate | undefined;
   160→  getAllNoteTemplates: () => NoteTemplate[];
   161→
   162→  // Actions - Daily Notes
   163→  getDailyNote: (date: Date) => Note | null;
   164→  createDailyNote: (date: Date) => Note;
   165→  getOrCreateDailyNote: (date: Date) => Note;
   166→
   167→  // P2: Block-level links & hover preview helpers
   168→  getBlockContent: (noteId: string, blockId: string) => string | null;
   169→  getNotePreview: (noteId: string, blockId?: string) => import('../types/notes').NotePreview | null;
   170→}
   171→
   172→/**
   173→ * Default note values
   174→ */
   175→const createDefaultNote = (overrides?: Partial<Note>): Note => {
   176→  const now = new Date();
   177→  return {
   178→    id: uuidv4(),
   179→    folderId: null,
   180→    title: NOTE_CONSTANTS.DEFAULT_TITLE,
   181→    content: '', // Empty Lexical state
   182→    contentText: '',
   183→    tags: [],
   184→    projectIds: [],
   185→    createdAt: now,
   186→    updatedAt: now,
   187→    isPinned: false,
   188→    isArchived: false,
   189→    ...overrides,
   190→  };
   191→};
   192→
   193→/**
   194→ * Sort notes based on sort config
   195→ */
   196→const sortNotes = (notes: Note[], config: NoteSortConfig): Note[] => {
   197→  const sorted = [...notes];
   198→
   199→  sorted.sort((a, b) => {
   200→    let comparison = 0;
   201→
   202→    switch (config.field) {
   203→      case 'title':
   204→        comparison = a.title.localeCompare(b.title);
   205→        break;
   206→      case 'createdAt':
   207→        comparison = a.createdAt.getTime() - b.createdAt.getTime();
   208→        break;
   209→      case 'updatedAt':
   210→        comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   211→        break;
   212→      case 'manual':
   213→        // Manual sort - preserve order (could add sortOrder field in future)
   214→        comparison = 0;
   215→        break;
   216→    }
   217→
   218→    return config.order === 'asc' ? comparison : -comparison;
   219→  });
   220→
   221→  // Always pin pinned notes to top
   222→  return sorted.sort((a, b) => {
   223→    if (a.isPinned && !b.isPinned) return -1;
   224→    if (!a.isPinned && b.isPinned) return 1;
   225→    return 0;
   226→  });
   227→};
   228→
   229→/**
   230→ * Filter notes based on filter type
   231→ */
   232→const filterNotes = (notes: Note[], filter: NoteFilter): Note[] => {
   233→  switch (filter) {
   234→    case 'favorites':
   235→      return notes.filter((note) => note.isFavorite);
   236→    case 'pinned':
   237→      return notes.filter((note) => note.isPinned);
   238→    case 'archived':
   239→      return notes.filter((note) => note.isArchived);
   240→    case 'unarchived':
   241→      return notes.filter((note) => !note.isArchived);
   242→    case 'all':
   243→    default:
   244→      return notes;
   245→  }
   246→};
   247→
   248→/**
   249→ * Create the Notes store
   250→ */
   251→export const useNotesStore = create<NotesStore>()(
   252→  persist(
   253→    (set, get) => ({
   254→      // Initial state
   255→      notes: {},
   256→      activeNoteId: null,
   257→      sortConfig: {
   258→        field: 'updatedAt',
   259→        order: 'desc',
   260→      },
   261→      filter: 'unarchived',
   262→      customNoteTemplates: [],
   263→
   264→      // CRUD Operations
   265→      createNote: (params) => {
   266→        const newNote = createDefaultNote(params);
   267→        set((state) => ({
   268→          notes: {
   269→            ...state.notes,
   270→            [newNote.id]: newNote,
   271→          },
   272→          activeNoteId: newNote.id, // Auto-select new note
   273→        }));
   274→        log.debug('Note created', { id: newNote.id });
   275→        return newNote;
   276→      },
   277→
   278→      getNote: (id) => {
   279→        return get().notes[id];
   280→      },
   281→
   282→      updateNote: (id, updates) => {
   283→        const note = get().notes[id];
   284→        if (!note) {
   285→          log.warn('Note not found', { id });
   286→          return;
   287→        }
   288→
   289→        // Only update timestamp if content/title/tags actually changed
   290→        // Skip timestamp update for UI-only changes (like folderId without content change)
   291→        const shouldUpdateTimestamp =
   292→          updates.content !== undefined ||
   293→          updates.title !== undefined ||
   294→          updates.tags !== undefined;
   295→
   296→        set((state) => ({
   297→          notes: {
   298→            ...state.notes,
   299→            [id]: {
   300→              ...note,
   301→              ...updates,
   302→              ...(shouldUpdateTimestamp ? { updatedAt: new Date() } : {}),
   303→            },
   304→          },
   305→        }));
   306→        log.debug('Note updated', { id, timestampUpdated: shouldUpdateTimestamp });
   307→      },
   308→
   309→      deleteNote: (id) => {
   310→        // Save note for undo
   311→        const noteToDelete = get().notes[id];
   312→        if (!noteToDelete) {
   313→          log.warn('Note not found', { id });
   314→          return;
   315→        }
   316→
   317→        // Store the previous activeNoteId for undo
   318→        const wasActive = get().activeNoteId === id;
   319→
   320→        // Delete the note
   321→        set((state) => {
   322→          const { [id]: deleted, ...remainingNotes } = state.notes;
   323→          return {
   324→            notes: remainingNotes,
   325→            activeNoteId: state.activeNoteId === id ? null : state.activeNoteId,
   326→          };
   327→        });
   328→
   329→        log.debug('Note deleted', { id });
   330→
   331→        // Delete associated images from IndexedDB (async, fire-and-forget)
   332→        import('../services/indexedDB').then(({ indexedDBService }) => {
   333→          indexedDBService.deleteNoteImages(id).catch((err) => {
   334→            log.error('Failed to delete note images', { id, error: err });
   335→          });
   336→        });
   337→
   338→        // Add undo action
   339→        useUndoStore.getState().addUndoAction(
   340→          `Note "${noteToDelete.title}" deleted`,
   341→          () => {
   342→            // Restore the note
   343→            set((state) => ({
   344→              notes: {
   345→                ...state.notes,
   346→                [id]: noteToDelete,
   347→              },
   348→              activeNoteId: wasActive ? id : state.activeNoteId,
   349→            }));
   350→            log.debug('Note restored (undo)', { id });
   351→          }
   352→        );
   353→      },
   354→
   355→      duplicateNote: (id) => {
   356→        const original = get().notes[id];
   357→        if (!original) {
   358→          log.warn('Note not found', { id });
   359→          return null;
   360→        }
   361→
   362→        const duplicate = createDefaultNote({
   363→          ...original,
   364→          title: `${original.title} (Copy)`,
   365→          isPinned: false, // Don't copy pin status
   366→        });
   367→
   368→        set((state) => ({
   369→          notes: {
   370→            ...state.notes,
   371→            [duplicate.id]: duplicate,
   372→          },
   373→        }));
   374→
   375→        log.debug('Note duplicated', { original: id, duplicate: duplicate.id });
   376→        return duplicate;
   377→      },
   378→
   379→      // Bulk operations
   380→      deleteNotes: (ids) => {
   381→        set((state) => {
   382→          const remainingNotes = { ...state.notes };
   383→          ids.forEach((id) => delete remainingNotes[id]);
   384→          return {
   385→            notes: remainingNotes,
   386→            activeNoteId: ids.includes(state.activeNoteId || '')
   387→              ? null
   388→              : state.activeNoteId,
   389→          };
   390→        });
   391→        log.debug('Deleted notes', { count: ids.length });
   392→
   393→        // Delete associated images from IndexedDB (async, fire-and-forget)
   394→        import('../services/indexedDB').then(({ indexedDBService }) => {
   395→          ids.forEach((id) => {
   396→            indexedDBService.deleteNoteImages(id).catch((err) => {
   397→              log.error('Failed to delete images for note', { id, error: err });
   398→            });
   399→          });
   400→        });
   401→      },
   402→
   403→      moveNotesToFolder: (noteIds, folderId) => {
   404→        set((state) => {
   405→          const updatedNotes = { ...state.notes };
   406→          noteIds.forEach((id) => {
   407→            if (updatedNotes[id]) {
   408→              updatedNotes[id] = {
   409→                ...updatedNotes[id],
   410→                folderId,
   411→                updatedAt: new Date(),
   412→              };
   413→            }
   414→          });
   415→          return { notes: updatedNotes };
   416→        });
   417→        log.debug('Moved notes to folder', { count: noteIds.length, folderId });
   418→      },
   419→
   420→      archiveNotes: (noteIds) => {
   421→        set((state) => {
   422→          const updatedNotes = { ...state.notes };
   423→          noteIds.forEach((id) => {
   424→            if (updatedNotes[id]) {
   425→              updatedNotes[id] = {
   426→                ...updatedNotes[id],
   427→                isArchived: true,
   428→                updatedAt: new Date(),
   429→              };
   430→            }
   431→          });
   432→          return { notes: updatedNotes };
   433→        });
   434→        log.debug('Archived notes', { count: noteIds.length });
   435→      },
   436→
   437→      unarchiveNotes: (noteIds) => {
   438→        set((state) => {
   439→          const updatedNotes = { ...state.notes };
   440→          noteIds.forEach((id) => {
   441→            if (updatedNotes[id]) {
   442→              updatedNotes[id] = {
   443→                ...updatedNotes[id],
   444→                isArchived: false,
   445→                updatedAt: new Date(),
   446→              };
   447→            }
   448→          });
   449→          return { notes: updatedNotes };
   450→        });
   451→        log.debug('Unarchived notes', { count: noteIds.length });
   452→      },
   453→
   454→      // Queries
   455→      getAllNotes: () => {
   456→        const state = get();
   457→        const notes = Object.values(state.notes);
   458→        const filtered = filterNotes(notes, state.filter);
   459→        return sortNotes(filtered, state.sortConfig);
   460→      },
   461→
   462→      getFilteredNotes: () => {
   463→        const { activeProjectIds } = useProjectContextStore.getState();
   464→        const state = get();
   465→        let notes = Object.values(state.notes);
   466→
   467→        // Apply archive filter
   468→        notes = filterNotes(notes, state.filter);
   469→
   470→        // "All" mode - no project filter applied
   471→        if (activeProjectIds.length === 0) {
   472→          return sortNotes(notes, state.sortConfig);
   473→        }
   474→
   475→        // Filter notes that have ANY of the active project IDs
   476→        const projectFiltered = notes.filter((note) =>
   477→          note.projectIds.some((pid) => activeProjectIds.includes(pid))
   478→        );
   479→
   480→        return sortNotes(projectFiltered, state.sortConfig);
   481→      },
   482→
   483→      getNotesByFolder: (folderId) => {
   484→        const state = get();
   485→        const notes = Object.values(state.notes).filter(
   486→          (note) => note.folderId === folderId
   487→        );
   488→        const filtered = filterNotes(notes, state.filter);
   489→        return sortNotes(filtered, state.sortConfig);
   490→      },
   491→
   492→      getNotesBy: (predicate) => {
   493→        const notes = Object.values(get().notes).filter(predicate);
   494→        return sortNotes(notes, get().sortConfig);
   495→      },
   496→
   497→      searchNotes: (query) => {
   498→        if (!query.trim()) return [];
   499→
   500→        const lowerQuery = query.toLowerCase();
   501→        const notes = Object.values(get().notes).filter((note) => {
   502→          // Search in title, content text, and tags
   503→          return (
   504→            note.title.toLowerCase().includes(lowerQuery) ||
   505→            note.contentText.toLowerCase().includes(lowerQuery) ||
   506→            note.tags.some((tag) => tag.toLowerCase().includes(lowerQuery))
   507→          );
   508→        });
   509→
   510→        return sortNotes(notes, get().sortConfig);
   511→      },
   512→
   513→      // Pin/Archive
   514→      togglePin: (id) => {
   515→        const note = get().notes[id];
   516→        if (!note) return;
   517→
   518→        set((state) => ({
   519→          notes: {
   520→            ...state.notes,
   521→            [id]: {
   522→              ...note,
   523→              isPinned: !note.isPinned,
   524→              updatedAt: new Date(),
   525→            },
   526→          },
   527→        }));
   528→        log.debug('Toggled pin', { id, isPinned: !note.isPinned });
   529→      },
   530→
   531→      toggleArchive: (id) => {
   532→        const note = get().notes[id];
   533→        if (!note) return;
   534→
   535→        set((state) => ({
   536→          notes: {
   537→            ...state.notes,
   538→            [id]: {
   539→              ...note,
   540→              isArchived: !note.isArchived,
   541→              updatedAt: new Date(),
   542→            },
   543→          },
   544→        }));
   545→        log.debug('Toggled archive', { id, isArchived: !note.isArchived });
   546→      },
   547→
   548→      toggleFavorite: (id) => {
   549→        const note = get().notes[id];
   550→        if (!note) return;
   551→
   552→        set((state) => ({
   553→          notes: {
   554→            ...state.notes,
   555→            [id]: {
   556→              ...note,
   557→              isFavorite: !note.isFavorite,
   558→              updatedAt: new Date(),
   559→            },
   560→          },
   561→        }));
   562→        log.debug('Toggled favorite', { id, isFavorite: !note.isFavorite });
   563→      },
   564→
   565→      // Tags
   566→      addTag: (id, tag) => {
   567→        const note = get().notes[id];
   568→        if (!note) return;
   569→
   570→        // Don't add duplicate tags
   571→        if (note.tags.includes(tag)) return;
   572→
   573→        // Check max tags limit
   574→        if (note.tags.length >= NOTE_CONSTANTS.MAX_TAGS) {
   575→          log.warn('Max tags reached', { max: NOTE_CONSTANTS.MAX_TAGS });
   576→          return;
   577→        }
   578→
   579→        set((state) => ({
   580→          notes: {
   581→            ...state.notes,
   582→            [id]: {
   583→              ...note,
   584→              tags: [...note.tags, tag],
   585→              updatedAt: new Date(),
   586→            },
   587→          },
   588→        }));
   589→        log.debug('Added tag', { id, tag });
   590→      },
   591→
   592→      removeTag: (id, tag) => {
   593→        const note = get().notes[id];
   594→        if (!note) return;
   595→
   596→        set((state) => ({
   597→          notes: {
   598→            ...state.notes,
   599→            [id]: {
   600→              ...note,
   601→              tags: note.tags.filter((t) => t !== tag),
   602→              updatedAt: new Date(),
   603→            },
   604→          },
   605→        }));
   606→        log.debug('Removed tag', { id, tag });
   607→      },
   608→
   609→      getAllTags: () => {
   610→        const notes = Object.values(get().notes);
   611→        const tagSet = new Set<string>();
   612→        notes.forEach((note) => {
   613→          note.tags.forEach((tag) => tagSet.add(tag));
   614→        });
   615→        return Array.from(tagSet).sort();
   616→      },
   617→
   618→      getTagUsageCounts: () => {
   619→        const notes = Object.values(get().notes);
   620→        const counts = new Map<string, number>();
   621→        notes.forEach((note) => {
   622→          note.tags.forEach((tag) => {
   623→            counts.set(tag, (counts.get(tag) || 0) + 1);
   624→          });
   625→        });
   626→        return counts;
   627→      },
   628→
   629→      renameTag: (oldTag, newTag) => {
