    33→    const margin = 20;
    34→    const maxWidth = pageWidth - 2 * margin;
    35→    let yPosition = margin;
    36→
    37→    // Helper: Add new page if needed
    38→    const checkPageBreak = (requiredSpace: number) => {
    39→      if (yPosition + requiredSpace > pageHeight - margin) {
    40→        doc.addPage();
