    42→      }
    43→    };
    44→
    45→    // Title
    46→    doc.setFontSize(20);
    47→    doc.setFont('helvetica', 'bold');
    48→    const titleLines = doc.splitTextToSize(note.title, maxWidth);
    49→    checkPageBreak(titleLines.length * 10);
    50→    doc.text(titleLines, margin, yPosition);
    51→    yPosition += titleLines.length * 10 + 10;
    52→
    53→    // Metadata (date, tags)
    54→    doc.setFontSize(10);
    55→    doc.setFont('helvetica', 'normal');
    56→    doc.setTextColor(100, 100, 100);
    57→
    58→    const dateStr = `Created: ${formatDate(note.createdAt)} | Updated: ${formatDate(note.updatedAt)}`;
    59→    checkPageBreak(5);
    60→    doc.text(dateStr, margin, yPosition);
    61→    yPosition += 5;
    62→
    63→    if (note.tags.length > 0) {
    64→      const tagsStr = `Tags: ${note.tags.join(', ')}`;
    65→      checkPageBreak(5);
    66→      doc.text(tagsStr, margin, yPosition);
    67→      yPosition += 5;
    68→    }
    69→
    70→    // Separator line
    71→    yPosition += 5;
    72→    checkPageBreak(2);
    73→    doc.setDrawColor(200, 200, 200);
    74→    doc.line(margin, yPosition, pageWidth - margin, yPosition);
    75→    yPosition += 10;
    76→
    77→    // Content (use contentText - plain text version)
    78→    doc.setFontSize(12);
    79→    doc.setFont('helvetica', 'normal');
    80→    doc.setTextColor(0, 0, 0);
    81→
    82→    if (note.contentText) {
    83→      // Split content by paragraphs (double newlines)
    84→      const paragraphs = note.contentText.split('\n\n').filter(p => p.trim());
    85→
    86→      for (const paragraph of paragraphs) {
    87→        // Split long paragraphs to fit page width
    88→        const lines = doc.splitTextToSize(paragraph.trim(), maxWidth);
    89→
    90→        // Check if paragraph fits on current page
    91→        const paragraphHeight = lines.length * 7; // 7mm per line
    92→        checkPageBreak(paragraphHeight);
    93→
    94→        // Add paragraph
    95→        doc.text(lines, margin, yPosition);
    96→        yPosition += paragraphHeight + 5; // 5mm spacing between paragraphs
    97→      }
    98→    } else {
    99→      // No content
   100→      doc.setTextColor(150, 150, 150);
   101→      doc.text('(No content)', margin, yPosition);
   102→    }
   103→
   104→    // Footer (page numbers)
   105→    const pageCount = (doc as any).internal.getNumberOfPages();
   106→    for (let i = 1; i <= pageCount; i++) {
   107→      doc.setPage(i);
   108→      doc.setFontSize(9);
   109→      doc.setTextColor(100, 100, 100);
   110→      doc.text(
   111→        `Page ${i} of ${pageCount}`,
   112→        pageWidth / 2,
   113→        pageHeight - 10,
   114→        { align: 'center' }
   115→      );
   116→    }
   117→
   118→    // Generate filename: note-title-YYYY-MM-DD.pdf
   119→    const filename = generateFilename(note.title);
   120→
   121→    // Save PDF
   122→    doc.save(filename);
   123→
   124→    console.log(`✅ Exported note to PDF: ${filename}`);
   125→
   126→    // Call success callback if provided
   127→    if (onSuccess) {
   128→      onSuccess(filename);
   129→    }
   130→  } catch (error) {
   131→    console.error('Failed to export note to PDF:', error);
   132→    throw new Error('Failed to export note to PDF');
   133→  }
   134→}
   135→
   136→/**
   137→ * Format date as YYYY-MM-DD
   138→ */
   139→function formatDate(date: Date): string {
   140→  const year = date.getFullYear();
   141→  const month = String(date.getMonth() + 1).padStart(2, '0');
   142→  const day = String(date.getDate()).padStart(2, '0');
   143→  return `${year}-${month}-${day}`;
   144→}
   145→
   146→/**
   147→ * Generate safe filename for PDF
   148→ * Sanitizes title and adds timestamp
   149→ */
   150→function generateFilename(title: string): string {
   151→  // Sanitize title (remove only filesystem-unsafe characters, keep apostrophes/periods/etc)
   152→  const safeTitle = title
   153→    .replace(/[<>:"/\\|?*]/g, '') // Only remove chars that break filesystems
   154→    .replace(/\s+/g, '-')
   155→    .toLowerCase()
   156→    .substring(0, 50); // Limit length
   157→
   158→  const timestamp = formatDate(new Date());
   159→  return `${safeTitle || 'note'}-${timestamp}.pdf`;
   160→}
